const warhammerQuestions = [
  {t:"m",q:"\u00bfQu\u00e9 universo de Warhammer est\u00e1 ambientado en el oscuro milenio 41?",o:["Warhammer Fantasy", "Warhammer 40,000", "Blood Bowl", "Mordheim"],a:1,exp:"Warhammer 40,000 transcurre principalmente en el milenio 41, una era de guerra eterna, fanatismo religioso y decadencia imperial.",extra:"Su tono se resume en la idea de que solo hay guerra. La humanidad sobrevive bajo el Imperio, una estructura gigantesca, brutal y teocr\u00e1tica que lucha contra xenos, demonios y traidores."},
  {t:"m",q:"\u00bfQui\u00e9n es el gobernante divinizado del Imperio de la Humanidad en Warhammer 40,000?",o:["Roboute Guilliman", "El Emperador de la Humanidad", "Horus Lupercal", "Malcador el Sigilita"],a:1,exp:"El Emperador de la Humanidad es el gobernante inmortal y divinizado del Imperio.",extra:"Aunque su cuerpo est\u00e1 casi muerto, permanece conectado al Trono Dorado de Terra. Para billones de humanos es un dios, aunque en vida rechaz\u00f3 expl\u00edcitamente la adoraci\u00f3n religiosa."},
  {t:"m",q:"\u00bfEn qu\u00e9 planeta se encuentra el Trono Dorado?",o:["Macragge", "Cadia", "Terra", "Mars"],a:2,exp:"El Trono Dorado se encuentra en Terra, la Tierra, capital sagrada del Imperio.",extra:"Terra es el centro pol\u00edtico y religioso de la humanidad. Desde all\u00ed el Astronomican gu\u00eda las naves humanas a trav\u00e9s de la Disformidad."},
  {t:"m",q:"\u00bfQu\u00e9 son los Adeptus Astartes?",o:["Guardias imperiales comunes", "Marines Espaciales modificados gen\u00e9ticamente", "Sacerdotes mec\u00e1nicos de Marte", "Navegantes mutantes"],a:1,exp:"Los Adeptus Astartes, o Marines Espaciales, son guerreros humanos modificados gen\u00e9tica, quir\u00fargica y psicol\u00f3gicamente.",extra:"Fueron creados a partir de la semilla gen\u00e9tica de los primarcas. Cada cap\u00edtulo tiene cultura, doctrina y defectos heredados de su linaje."},
  {t:"m",q:"\u00bfQui\u00e9nes fueron los primarcas?",o:["Dioses del Caos", "Hijos gen\u00e9ticos del Emperador y padres de las Legiones Astartes", "Generales de la Guardia Imperial", "L\u00edderes de los Eldar"],a:1,exp:"Los primarcas fueron seres sobrehumanos creados por el Emperador como l\u00edderes de las Legiones de Marines Espaciales.",extra:"Cada primarca encarnaba aspectos distintos del Emperador: estrategia, furia, perfecci\u00f3n, resistencia, carisma o secreto. Su dispersi\u00f3n por la galaxia marc\u00f3 el destino de sus legiones."},
  {t:"m",q:"\u00bfQu\u00e9 evento dividi\u00f3 a los Marines Espaciales entre leales y traidores?",o:["La Ca\u00edda de Cadia", "La Herej\u00eda de Horus", "La Guerra de Armageddon", "La Cruzada Damocles"],a:1,exp:"La Herej\u00eda de Horus fue la guerra civil gal\u00e1ctica que enfrent\u00f3 al Emperador contra Horus y las legiones traidoras.",extra:"Es el gran mito tr\u00e1gico de Warhammer 40,000: los hijos del Emperador se volvieron contra \u00e9l, casi destruyendo el sue\u00f1o de unidad humana."},
  {t:"m",q:"\u00bfQui\u00e9n lider\u00f3 la rebeli\u00f3n contra el Emperador durante la Herej\u00eda?",o:["Lorgar", "Horus Lupercal", "Abaddon", "Magnus el Rojo"],a:1,exp:"Horus Lupercal, primarca de los Lobos Lunares, lider\u00f3 la rebeli\u00f3n contra el Emperador.",extra:"Horus era el hijo favorito del Emperador y Se\u00f1or de la Guerra de la Gran Cruzada. Su ca\u00edda hizo que la traici\u00f3n fuera mucho m\u00e1s devastadora."},
  {t:"m",q:"\u00bfQu\u00e9 Legi\u00f3n fue comandada por Roboute Guilliman?",o:["Ultramarines", "\u00c1ngeles Sangrientos", "Pu\u00f1os Imperiales", "Lobos Espaciales"],a:0,exp:"Roboute Guilliman fue el primarca de los Ultramarines.",extra:"Guilliman es famoso por su talento administrativo y estrat\u00e9gico. Despu\u00e9s de la Herej\u00eda escribi\u00f3 el Codex Astartes, que reorganiz\u00f3 a los Marines Espaciales en cap\u00edtulos."},
  {t:"m",q:"\u00bfQu\u00e9 documento reorganiz\u00f3 a los Marines Espaciales tras la Herej\u00eda?",o:["Codex Astartes", "Libro de Lorgar", "Tratado de Marte", "Edicto de Terra"],a:0,exp:"El Codex Astartes fue escrito por Roboute Guilliman para dividir las antiguas legiones en cap\u00edtulos m\u00e1s peque\u00f1os.",extra:"Su objetivo era evitar que una sola fuerza militar tuviera suficiente poder para repetir una traici\u00f3n como la de Horus."},
  {t:"m",q:"\u00bfQu\u00e9 cap\u00edtulo de Marines Espaciales es considerado el ejemplo m\u00e1s codex-compliant?",o:["Ultramarines", "Templarios Negros", "Lobos Espaciales", "\u00c1ngeles Oscuros"],a:0,exp:"Los Ultramarines son el ejemplo cl\u00e1sico de cap\u00edtulo que sigue el Codex Astartes.",extra:"Por eso suelen representarse como el modelo est\u00e1ndar de organizaci\u00f3n Astartes, aunque esto tambi\u00e9n los hizo objeto de bromas entre fans por ser \u201cdemasiado perfectos\u201d."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los \u00c1ngeles Sangrientos?",o:["Sanguinius", "Lion El Jonson", "Ferrus Manus", "Vulkan"],a:0,exp:"Sanguinius fue el primarca de los \u00c1ngeles Sangrientos.",extra:"Sanguinius era amado por su nobleza y alas angelicales. Su muerte a manos de Horus dej\u00f3 una herida ps\u00edquica en sus hijos conocida como la Rabia Negra."},
  {t:"m",q:"\u00bfQu\u00e9 maldici\u00f3n sufren los \u00c1ngeles Sangrientos al revivir la muerte de Sanguinius?",o:["Rabia Negra", "Sed Roja", "Carne cambiante", "Maldici\u00f3n del Wulfen"],a:0,exp:"La Rabia Negra hace que algunos \u00c1ngeles Sangrientos crean estar viviendo la batalla final de Sanguinius contra Horus.",extra:"Los afectados son enviados a la Compa\u00f1\u00eda de la Muerte, donde buscan una muerte honorable en batalla."},
  {t:"m",q:"\u00bfQu\u00e9 otro defecto gen\u00e9tico caracteriza a los \u00c1ngeles Sangrientos?",o:["Sed Roja", "Piel p\u00e9trea", "Mutaci\u00f3n lupina", "Ceguera espiritual"],a:0,exp:"La Sed Roja es una compulsi\u00f3n vamp\u00edrica por la sangre que afecta a los \u00c1ngeles Sangrientos.",extra:"Este defecto contrasta con su est\u00e9tica noble y angelical, creando una tensi\u00f3n central en el cap\u00edtulo: belleza, arte, nobleza y monstruosidad interior."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los \u00c1ngeles Oscuros?",o:["Lion El Jonson", "Rogal Dorn", "Corvus Corax", "Jaghatai Khan"],a:0,exp:"Lion El Jonson fue el primarca de los \u00c1ngeles Oscuros.",extra:"Los \u00c1ngeles Oscuros guardan el secreto de los Ca\u00eddos, antiguos hermanos que traicionaron durante la Herej\u00eda. Ese secreto define gran parte de su identidad."},
  {t:"m",q:"\u00bfC\u00f3mo se llama el secreto grupo de traidores que obsesiona a los \u00c1ngeles Oscuros?",o:["Los Ca\u00eddos", "Los Condenados", "Los Rotos", "Los Exiliados"],a:0,exp:"Los Ca\u00eddos son antiguos \u00c1ngeles Oscuros que se rebelaron o fueron arrastrados por la traici\u00f3n.",extra:"El cap\u00edtulo dedica enormes recursos a cazarlos en secreto, incluso si eso implica abandonar aliados o misiones imperiales."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los Pu\u00f1os Imperiales?",o:["Rogal Dorn", "Perturabo", "Leman Russ", "Konrad Curze"],a:0,exp:"Rogal Dorn fue el primarca de los Pu\u00f1os Imperiales.",extra:"Dorn fue el gran fortificador de Terra durante el Asedio. Su rivalidad con Perturabo de los Guerreros de Hierro es una de las m\u00e1s amargas de la Herej\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 cap\u00edtulo sucesor de los Pu\u00f1os Imperiales es famoso por sus cruzadas eternas?",o:["Templarios Negros", "Lamentadores", "Exorcistas", "Mentores"],a:0,exp:"Los Templarios Negros son un cap\u00edtulo sucesor de los Pu\u00f1os Imperiales conocido por su fervor religioso y cruzadas permanentes.",extra:"A diferencia de muchos cap\u00edtulos, no siguen estrictamente el l\u00edmite de mil marines del Codex y operan como grandes cruzadas dispersas."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los Lobos Espaciales?",o:["Leman Russ", "Magnus el Rojo", "Angron", "Mortarion"],a:0,exp:"Leman Russ fue el primarca de los Lobos Espaciales.",extra:"Los Lobos Espaciales combinan est\u00e9tica vikinga, ferocidad tribal y una independencia inc\u00f3moda frente a las instituciones imperiales."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal tienen los Lobos Espaciales?",o:["Fenris", "Baal", "Caliban", "Nocturne"],a:0,exp:"Fenris es el mundo natal de los Lobos Espaciales.",extra:"Es un planeta brutal de hielo, mares violentos y culturas guerreras. Sobrevivir all\u00ed ya es una prueba antes de convertirse en Astartes."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los Cicatrices Blancas?",o:["Jaghatai Khan", "Vulkan", "Rogal Dorn", "Fulgrim"],a:0,exp:"Jaghatai Khan fue el primarca de los Cicatrices Blancas.",extra:"Su legi\u00f3n se especializa en velocidad, guerra m\u00f3vil y ataques rel\u00e1mpago, con inspiraci\u00f3n cultural de pueblos n\u00f3madas de las estepas."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a la Guardia del Cuervo?",o:["Corvus Corax", "Konrad Curze", "Alpharius", "Ferrus Manus"],a:0,exp:"Corvus Corax fue el primarca de la Guardia del Cuervo.",extra:"La Guardia del Cuervo es experta en sigilo, guerrilla y ataques quir\u00fargicos, marcada por las p\u00e9rdidas terribles de la Masacre de Isstvan V."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a los Salamandras?",o:["Vulkan", "Ferrus Manus", "Sanguinius", "Rogal Dorn"],a:0,exp:"Vulkan fue el primarca de los Salamandras.",extra:"Los Salamandras son conocidos por su conexi\u00f3n con civiles humanos, su resistencia y su amor por armas de fuego, martillos y forja."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal tienen los Salamandras?",o:["Nocturne", "Fenris", "Baal", "Macragge"],a:0,exp:"Nocturne es el mundo natal volc\u00e1nico de los Salamandras.",extra:"Su ambiente extremo moldea su cultura de herreros, paciencia, resistencia y protecci\u00f3n comunitaria."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lider\u00f3 a las Manos de Hierro?",o:["Ferrus Manus", "Vulkan", "Perturabo", "Mortarion"],a:0,exp:"Ferrus Manus fue el primarca de las Manos de Hierro.",extra:"Su muerte temprana en Isstvan V marc\u00f3 profundamente a su legi\u00f3n, reforzando su obsesi\u00f3n con reemplazar carne por m\u00e1quina."},
  {t:"m",q:"\u00bfCu\u00e1l es la frase filos\u00f3fica central de las Manos de Hierro?",o:["La carne es d\u00e9bil", "El fuego purifica", "La velocidad es vida", "El honor lo es todo"],a:0,exp:"Las Manos de Hierro creen que \u201cla carne es d\u00e9bil\u201d.",extra:"Su obsesi\u00f3n por la bi\u00f3nica y el autocastigo nace del trauma de haber perdido a Ferrus Manus y de culpar a la debilidad emocional."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Devoradores de Mundos?",o:["Angron", "Mortarion", "Fulgrim", "Perturabo"],a:0,exp:"Angron fue el primarca de los Devoradores de Mundos.",extra:"Los Clavos del Carnicero implantados en su cerebro lo condenaron a una existencia de dolor, furia y violencia constante."},
  {t:"m",q:"\u00bfA qu\u00e9 dios del Caos sirven principalmente los Devoradores de Mundos?",o:["Khorne", "Tzeentch", "Nurgle", "Slaanesh"],a:0,exp:"Los Devoradores de Mundos sirven principalmente a Khorne, dios de la sangre y la guerra.",extra:"Su grito \u201c\u00a1Sangre para el Dios de la Sangre!\u201d resume su culto a la violencia directa, brutal y sin sutileza."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a la Guardia de la Muerte?",o:["Mortarion", "Magnus", "Lorgar", "Curze"],a:0,exp:"Mortarion fue el primarca de la Guardia de la Muerte.",extra:"Tras caer en el Caos, la Guardia de la Muerte se consagr\u00f3 a Nurgle, convirti\u00e9ndose en una legi\u00f3n podrida, resistente y pestilente."},
  {t:"m",q:"\u00bfA qu\u00e9 dios del Caos sirve la Guardia de la Muerte?",o:["Nurgle", "Khorne", "Slaanesh", "Tzeentch"],a:0,exp:"La Guardia de la Muerte sirve a Nurgle, dios de la plaga, la decadencia y la resistencia corrupta.",extra:"Nurgle no solo representa enfermedad, sino una forma retorcida de aceptaci\u00f3n, estancamiento y falsa alegr\u00eda ante la putrefacci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Mil Hijos?",o:["Magnus el Rojo", "Lorgar", "Fulgrim", "Horus"],a:0,exp:"Magnus el Rojo fue el primarca de los Mil Hijos.",extra:"Magnus era un ps\u00edquico extraordinario. Su intento de advertir al Emperador sobre Horus termin\u00f3 rompiendo barreras ps\u00edquicas y agravando la tragedia."},
  {t:"m",q:"\u00bfA qu\u00e9 dios del Caos se asocian los Mil Hijos?",o:["Tzeentch", "Khorne", "Nurgle", "Slaanesh"],a:0,exp:"Los Mil Hijos est\u00e1n asociados a Tzeentch, dios del cambio, la magia y la manipulaci\u00f3n.",extra:"La R\u00fabrica de Ahriman convirti\u00f3 a muchos de sus marines en armaduras vac\u00edas llenas de polvo, buscando salvarlos de la mutaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 hechicero lanz\u00f3 la R\u00fabrica que transform\u00f3 a los Mil Hijos?",o:["Ahriman", "Kharn", "Typhus", "Erebus"],a:0,exp:"Ahriman lanz\u00f3 la R\u00fabrica para detener la degeneraci\u00f3n mutante de su legi\u00f3n.",extra:"El resultado fue desastroso: los ps\u00edquicos sobrevivieron potenciados, pero la mayor\u00eda de la legi\u00f3n qued\u00f3 convertida en aut\u00f3matas de polvo."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Hijos del Emperador?",o:["Fulgrim", "Lorgar", "Perturabo", "Angron"],a:0,exp:"Fulgrim fue el primarca de los Hijos del Emperador.",extra:"Su b\u00fasqueda de perfecci\u00f3n acab\u00f3 degenerando en exceso, orgullo y corrupci\u00f3n por Slaanesh."},
  {t:"m",q:"\u00bfA qu\u00e9 dios del Caos sirven los Hijos del Emperador?",o:["Slaanesh", "Khorne", "Nurgle", "Tzeentch"],a:0,exp:"Los Hijos del Emperador est\u00e1n consagrados a Slaanesh, dios del exceso, placer, perfecci\u00f3n y obsesi\u00f3n.",extra:"Su ca\u00edda es especialmente tr\u00e1gica porque empez\u00f3 en la b\u00fasqueda de excelencia y belleza, corrompida hasta convertirse en horror sensorial."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Portadores de la Palabra?",o:["Lorgar", "Horus", "Mortarion", "Curze"],a:0,exp:"Lorgar fue el primarca de los Portadores de la Palabra.",extra:"Lorgar fue castigado por adorar al Emperador como dios. Esa humillaci\u00f3n lo empuj\u00f3 hacia los dioses del Caos, convirti\u00e9ndolo en uno de los arquitectos espirituales de la Herej\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 legi\u00f3n traidora fue clave en difundir la adoraci\u00f3n al Caos?",o:["Portadores de la Palabra", "Guerreros de Hierro", "Amos de la Noche", "Legi\u00f3n Alfa"],a:0,exp:"Los Portadores de la Palabra fueron fundamentales para propagar la fe en los dioses del Caos.",extra:"A diferencia de otros traidores motivados por orgullo o resentimiento, su traici\u00f3n fue profundamente religiosa."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Guerreros de Hierro?",o:["Perturabo", "Rogal Dorn", "Ferrus Manus", "Alpharius"],a:0,exp:"Perturabo fue el primarca de los Guerreros de Hierro.",extra:"Perturabo era un maestro de la guerra de asedio, resentido por ser usado constantemente en campa\u00f1as brutales y poco gloriosas."},
  {t:"m",q:"\u00bfCu\u00e1l es el gran rival lealista de Perturabo?",o:["Rogal Dorn", "Sanguinius", "Vulkan", "Jaghatai Khan"],a:0,exp:"Rogal Dorn y Perturabo son rivales por su dominio de fortificaci\u00f3n y asedio.",extra:"Su enemistad simboliza dos formas opuestas de ingenier\u00eda militar: defensa implacable contra destrucci\u00f3n met\u00f3dica."},
  {t:"m",q:"\u00bfQu\u00e9 primarca traidor lider\u00f3 a los Amos de la Noche?",o:["Konrad Curze", "Corvus Corax", "Angron", "Fulgrim"],a:0,exp:"Konrad Curze fue el primarca de los Amos de la Noche.",extra:"Curze cre\u00eda en imponer orden mediante terror absoluto. Sus visiones del futuro y su brutalidad lo convirtieron en una figura tr\u00e1gica y monstruosa."},
  {t:"m",q:"\u00bfQu\u00e9 legi\u00f3n traidora es famosa por usar miedo y terror psicol\u00f3gico?",o:["Amos de la Noche", "Mil Hijos", "Guardia de la Muerte", "Hijos del Emperador"],a:0,exp:"Los Amos de la Noche usan terror, tortura y guerra psicol\u00f3gica como herramientas principales.",extra:"Su est\u00e9tica de criminales, pieles desolladas y oscuridad expresa una doctrina simple: vencer destruyendo la voluntad del enemigo."},
  {t:"m",q:"\u00bfQu\u00e9 primarca o primarcas lideraron a la Legi\u00f3n Alfa?",o:["Alpharius y Omegon", "Horus y Lorgar", "Ferrus y Vulkan", "Curze y Corax"],a:0,exp:"La Legi\u00f3n Alfa est\u00e1 asociada a los gemelos Alpharius y Omegon.",extra:"Su lore est\u00e1 lleno de mentiras, identidades falsas e infiltraci\u00f3n. Incluso decir qui\u00e9n lidera realmente a la Legi\u00f3n Alfa suele ser parte del misterio."},
  {t:"m",q:"\u00bfCu\u00e1l es la frase m\u00e1s asociada a la Legi\u00f3n Alfa?",o:["Yo soy Alpharius", "La carne es d\u00e9bil", "Sangre para el Dios de la Sangre", "Valor y honor"],a:0,exp:"\u201cYo soy Alpharius\u201d es la frase emblem\u00e1tica de la Legi\u00f3n Alfa.",extra:"Refleja su doctrina de anonimato, c\u00e9lulas encubiertas y confusi\u00f3n total sobre identidad y mando."},
  {t:"m",q:"\u00bfQui\u00e9n es Abaddon el Saqueador?",o:["Se\u00f1or de la Guerra del Caos y heredero de Horus", "Primarca de los Ultramarines", "Capit\u00e1n de los Custodes", "Un inquisidor radical"],a:0,exp:"Abaddon es el l\u00edder de los Marines Espaciales del Caos y antiguo primer capit\u00e1n de Horus.",extra:"Tras la Herej\u00eda, rechaz\u00f3 ser solo una copia de Horus y lider\u00f3 las Cruzadas Negras contra el Imperio."},
  {t:"m",q:"\u00bfQu\u00e9 fortaleza imperial cay\u00f3 durante la 13\u00aa Cruzada Negra?",o:["Cadia", "Macragge", "Baal", "Armageddon"],a:0,exp:"Cadia cay\u00f3 durante la 13\u00aa Cruzada Negra de Abaddon.",extra:"La frase \u201cCadia stands\u201d sigue viva porque, aunque el planeta fue destruido, la resistencia cadiana se convirti\u00f3 en s\u00edmbolo de desaf\u00edo imperial."},
  {t:"m",q:"\u00bfQu\u00e9 gran fractura dividi\u00f3 la galaxia tras la ca\u00edda de Cadia?",o:["Cicatrix Maledictum", "Ojo del Terror", "Tormenta Damocles", "Fisura de Baal"],a:0,exp:"La Cicatrix Maledictum, o Gran Cicatriz, parti\u00f3 la galaxia en dos.",extra:"Esta herida de disformidad dej\u00f3 a medio Imperio casi aislado de la luz del Astronomican, creando el Imperium Nihilus."},
  {t:"m",q:"\u00bfQu\u00e9 regi\u00f3n de la galaxia queda aislada y oscurecida por la Gran Cicatriz?",o:["Imperium Nihilus", "Segmentum Solar", "Ultima Founding", "Halo Stars"],a:0,exp:"El Imperium Nihilus queda al otro lado de la Cicatrix Maledictum, con comunicaciones y navegaci\u00f3n devastadas.",extra:"Es una de las zonas m\u00e1s desesperadas del Imperio moderno, donde mundos humanos sobreviven con poco apoyo de Terra."},
  {t:"m",q:"\u00bfQu\u00e9 primarca lealista regres\u00f3 para liderar el Imperio en la era moderna?",o:["Roboute Guilliman", "Sanguinius", "Ferrus Manus", "Rogal Dorn"],a:0,exp:"Roboute Guilliman regres\u00f3 y asumi\u00f3 el mando del Imperio como Lord Comandante.",extra:"Su regreso es ir\u00f3nico y tr\u00e1gico: despierta en un Imperio religioso, supersticioso y burocr\u00e1tico que contradice buena parte del sue\u00f1o original del Emperador."},
  {t:"m",q:"\u00bfQu\u00e9 son los Primaris Space Marines?",o:["Una nueva generaci\u00f3n de Astartes mejorados", "Demonios del Caos redimidos", "Guardias imperiales con armadura pesada", "Custodes menores"],a:0,exp:"Los Primaris son Marines Espaciales mejorados creados por Belisarius Cawl durante milenios.",extra:"Fueron desplegados durante la Cruzada Indomitus de Guilliman para reforzar cap\u00edtulos devastados y fundar nuevos cap\u00edtulos."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 a los Primaris Space Marines?",o:["Belisarius Cawl", "Fabius Bile", "Roboute Guilliman", "Arkhan Land"],a:0,exp:"Belisarius Cawl, archmagos del Adeptus Mechanicus, desarroll\u00f3 los Primaris.",extra:"Cawl trabaj\u00f3 durante diez mil a\u00f1os con tecnolog\u00eda, semilla gen\u00e9tica y \u00f3rdenes antiguas de Guilliman."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n imperial adora al Dios M\u00e1quina?",o:["Adeptus Mechanicus", "Adeptus Ministorum", "Adeptus Arbites", "Astra Militarum"],a:0,exp:"El Adeptus Mechanicus venera al Dios M\u00e1quina y custodia la tecnolog\u00eda del Imperio.",extra:"Para el Mechanicus, reparar una m\u00e1quina es tanto ingenier\u00eda como ritual religioso. Su relaci\u00f3n con la innovaci\u00f3n es ambigua, temerosa y profundamente dogm\u00e1tica."},
  {t:"m",q:"\u00bfCu\u00e1l es el mundo sagrado principal del Adeptus Mechanicus?",o:["Mars", "Terra", "Lucius", "Ryza"],a:0,exp:"Marte es el mundo forja m\u00e1s sagrado del Adeptus Mechanicus.",extra:"El pacto entre Terra y Marte fue fundamental para la Gran Cruzada. El Imperio depende de los mundos forja para armas, naves, titanes y mantenimiento tecnol\u00f3gico."},
  {t:"m",q:"\u00bfQu\u00e9 son los Titanes en Warhammer 40,000?",o:["M\u00e1quinas de guerra colosales pilotadas por pr\u00edncipes y tripulaciones", "Naves Eldar peque\u00f1as", "Demonios de Khorne", "Tanques ligeros de exploraci\u00f3n"],a:0,exp:"Los Titanes son enormes m\u00e1quinas de guerra del Adeptus Titanicus.",extra:"Un solo Tit\u00e1n puede cambiar el curso de una guerra planetaria. Para el Mechanicus, son casi avatares vivientes del Dios M\u00e1quina."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n imperial est\u00e1 formada por soldados humanos comunes en cantidades inmensas?",o:["Astra Militarum", "Adeptus Custodes", "Grey Knights", "Officio Assassinorum"],a:0,exp:"El Astra Militarum, o Guardia Imperial, re\u00fane ej\u00e9rcitos humanos masivos.",extra:"A diferencia de los Marines Espaciales, los guardias son mortales comunes enfrentando horrores imposibles con disciplina, artiller\u00eda y n\u00fameros absurdos."},
  {t:"m",q:"\u00bfQu\u00e9 regimiento imperial es famoso por resistir en Cadia?",o:["Cadianos", "Catachanes", "Mordianos", "Vostroyanos"],a:0,exp:"Los Cadianos son el regimiento emblem\u00e1tico del mundo fortaleza Cadia.",extra:"Incluso despu\u00e9s de la destrucci\u00f3n de su planeta, los regimientos cadianos siguen luchando por toda la galaxia."},
  {t:"m",q:"\u00bfQu\u00e9 regimiento imperial es famoso por luchar en junglas letales?",o:["Catachanes", "Cadianos", "Krieg", "Tallarn"],a:0,exp:"Los Catachanes vienen de un mundo selv\u00e1tico mortal y son expertos en guerra de jungla.",extra:"Catachan es tan peligroso que sobrevivir all\u00ed convierte a sus habitantes en soldados duros, musculosos y especialistas en emboscadas."},
  {t:"m",q:"\u00bfQu\u00e9 regimiento imperial es conocido por su est\u00e9tica de guerra de trincheras y m\u00e1scaras de gas?",o:["Death Korps of Krieg", "Catachanes", "Elysianos", "Mordianos"],a:0,exp:"El Death Korps of Krieg es famoso por su guerra de desgaste, trincheras y disposici\u00f3n al sacrificio.",extra:"Krieg es un mundo marcado por culpa y expiaci\u00f3n. Sus soldados consideran la muerte en servicio al Emperador casi una deuda sagrada."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n imperial est\u00e1 formada por las guerreras religiosas conocidas como Hermanas de Batalla?",o:["Adepta Sororitas", "Adeptus Custodes", "Sisters of Silence", "Officio Assassinorum"],a:0,exp:"Las Adepta Sororitas, o Hermanas de Batalla, son la fuerza militar del Adeptus Ministorum.",extra:"Combinan fe fan\u00e1tica, disciplina militar y armamento imperial pesado. Su fervor puede manifestarse en milagros en el campo de batalla."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n protege directamente al Emperador en Terra?",o:["Adeptus Custodes", "Astra Militarum", "Ultramarines", "Inquisici\u00f3n"],a:0,exp:"Los Adeptus Custodes son los guardianes personales del Emperador.",extra:"Son m\u00e1s antiguos y superiores individualmente a los Astartes, creados como obras maestras gen\u00e9ticas \u00fanicas, no como soldados producidos en masa."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n imperial caza herejes, demonios y amenazas internas?",o:["Inquisici\u00f3n", "Adeptus Mechanicus", "Navis Nobilite", "Administratum"],a:0,exp:"La Inquisici\u00f3n investiga y elimina amenazas al Imperio desde dentro y fuera.",extra:"Sus inquisidores tienen autoridad casi ilimitada, lo que los convierte tanto en defensores necesarios como en figuras potencialmente aterradoras."},
  {t:"m",q:"\u00bfQu\u00e9 Ordo de la Inquisici\u00f3n se enfoca en demonios?",o:["Ordo Malleus", "Ordo Xenos", "Ordo Hereticus", "Ordo Chronos"],a:0,exp:"El Ordo Malleus combate demonios y amenazas del Caos.",extra:"Trabaja estrechamente con los Caballeros Grises, un cap\u00edtulo secreto de Marines especializado en guerra demon\u00edaca."},
  {t:"m",q:"\u00bfQu\u00e9 Ordo de la Inquisici\u00f3n se enfoca en alien\u00edgenas?",o:["Ordo Xenos", "Ordo Malleus", "Ordo Hereticus", "Ordo Sicarius"],a:0,exp:"El Ordo Xenos combate, estudia y contiene amenazas alien\u00edgenas.",extra:"Su relaci\u00f3n con especies xenos puede ir desde exterminio absoluto hasta uso pragm\u00e1tico de informaci\u00f3n o tecnolog\u00eda prohibida."},
  {t:"m",q:"\u00bfQu\u00e9 Ordo de la Inquisici\u00f3n se enfoca en herej\u00eda interna?",o:["Ordo Hereticus", "Ordo Xenos", "Ordo Malleus", "Ordo Sepulturum"],a:0,exp:"El Ordo Hereticus combate herej\u00edas, brujas, cultos y corrupci\u00f3n dentro de la humanidad.",extra:"Suele trabajar con las Adepta Sororitas y se ocupa de que la fe imperial no se desv\u00ede de formas peligrosas."},
  {t:"m",q:"\u00bfQu\u00e9 cap\u00edtulo de Marines es famoso por luchar contra demonios y mantener su existencia en secreto?",o:["Caballeros Grises", "Ultramarines", "Pu\u00f1os Imperiales", "Templarios Negros"],a:0,exp:"Los Caballeros Grises son un cap\u00edtulo secreto especializado en combatir demonios.",extra:"Todos sus miembros son ps\u00edquicos entrenados y su semilla gen\u00e9tica est\u00e1 asociada directamente al Emperador."},
  {t:"m",q:"\u00bfQu\u00e9 dimensi\u00f3n paralela alimentada por emociones se conoce como la Disformidad?",o:["Warp", "Webway", "Materium", "Noosfera"],a:0,exp:"La Disformidad, o Warp, es una dimensi\u00f3n ps\u00edquica usada para viajes interestelares y magia peligrosa.",extra:"Es necesaria para el Imperio, pero est\u00e1 habitada por demonios y entidades del Caos. Toda navegaci\u00f3n por ella es una apuesta con la locura."},
  {t:"m",q:"\u00bfQu\u00e9 se\u00f1al ps\u00edquica gu\u00eda a las naves humanas a trav\u00e9s de la Disformidad?",o:["Astronomican", "Cicatrix", "Noctilith", "Webway Beacon"],a:0,exp:"El Astronomican es un faro ps\u00edquico alimentado desde Terra que gu\u00eda a los navegantes humanos.",extra:"Depende del Emperador y de sacrificios ps\u00edquicos constantes. Sin \u00e9l, el Imperio colapsar\u00eda en islas aisladas."},
  {t:"m",q:"\u00bfQu\u00e9 mutantes humanos permiten navegar por la Disformidad?",o:["Navegantes", "Servitors", "Blankos", "Ogryns"],a:0,exp:"Los Navegantes poseen un tercer ojo mutante que les permite percibir rutas en la Disformidad.",extra:"Pertenecen a casas nobles muy poderosas, imprescindibles para el viaje interestelar imperial."},
  {t:"m",q:"\u00bfQu\u00e9 tipo de individuo anula o perturba fen\u00f3menos ps\u00edquicos por su ausencia de alma en la Disformidad?",o:["Blank o paria", "Ps\u00edquico alfa", "Navegante", "Tecnosacerdote"],a:0,exp:"Los blanks, parias o intocables tienen una presencia antips\u00edquica que incomoda a ps\u00edquicos y demonios.",extra:"Las Hermanas del Silencio son blanks entrenadas, usadas hist\u00f3ricamente junto a los Custodes contra amenazas ps\u00edquicas."},
  {t:"m",q:"\u00bfQui\u00e9nes son los cuatro grandes dioses del Caos?",o:["Khorne, Tzeentch, Nurgle y Slaanesh", "Gork, Mork, Khaine y Isha", "Sigmar, Nagash, Grungni y Teclis", "Morr, Ulric, Taal y Ranald"],a:0,exp:"Los cuatro grandes dioses del Caos son Khorne, Tzeentch, Nurgle y Slaanesh.",extra:"Cada uno se alimenta de emociones y aspectos extremos: violencia, cambio, decadencia y exceso."},
  {t:"m",q:"\u00bfQu\u00e9 dios del Caos odia especialmente la magia y valora el combate directo?",o:["Khorne", "Tzeentch", "Nurgle", "Slaanesh"],a:0,exp:"Khorne favorece la sangre, la guerra y el combate directo, y desprecia la hechicer\u00eda cobarde.",extra:"Sus seguidores buscan matar y derramar sangre, sin importar demasiado de qui\u00e9n sea, mientras haya violencia."},
  {t:"m",q:"\u00bfQu\u00e9 dios del Caos est\u00e1 asociado al cambio, magia y planes infinitos?",o:["Tzeentch", "Khorne", "Nurgle", "Slaanesh"],a:0,exp:"Tzeentch es el dios del cambio, la hechicer\u00eda, la ambici\u00f3n y la manipulaci\u00f3n.",extra:"Sus planes suelen ser tan complejos que incluso sus seguidores pueden ser piezas sacrificables dentro de conspiraciones imposibles."},
  {t:"m",q:"\u00bfQu\u00e9 dios del Caos est\u00e1 asociado a enfermedad, putrefacci\u00f3n y falsa jovialidad?",o:["Nurgle", "Khorne", "Slaanesh", "Tzeentch"],a:0,exp:"Nurgle es el dios de la plaga, decadencia y resistencia morbosa.",extra:"Sus seguidores suelen aceptar la enfermedad como regalo, encontrando alegr\u00eda grotesca en la podredumbre."},
  {t:"m",q:"\u00bfQu\u00e9 dios del Caos naci\u00f3 de la ca\u00edda de los Eldar?",o:["Slaanesh", "Khorne", "Nurgle", "Tzeentch"],a:0,exp:"Slaanesh naci\u00f3 del exceso ps\u00edquico y decadencia de la antigua civilizaci\u00f3n Eldar.",extra:"Su nacimiento cre\u00f3 el Ojo del Terror y devor\u00f3 gran parte de las almas Eldar, dejando a su especie al borde de la extinci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 especie antigua provoc\u00f3 la creaci\u00f3n de Slaanesh por sus excesos?",o:["Eldar/Aeldari", "Orkos", "Necrones", "T\u2019au"],a:0,exp:"Los Eldar, ahora llamados Aeldari, provocaron involuntariamente el nacimiento de Slaanesh.",extra:"Su imperio era tan avanzado y hedonista que sus emociones extremas dieron forma a un dios del Caos."},
  {t:"m",q:"\u00bfC\u00f3mo se llaman las enormes naves-mundo de los Aeldari supervivientes?",o:["Mundos Astronave", "Mundos Forja", "Mundos Tumba", "Fortalezas Negras"],a:0,exp:"Los Craftworlds o Mundos Astronave son gigantescas naves donde viven muchos Aeldari supervivientes.",extra:"Cada mundo astronave tiene cultura propia y caminos estrictos para evitar caer otra vez en el exceso que cre\u00f3 a Slaanesh."},
  {t:"m",q:"\u00bfQu\u00e9 Aeldari viven en Commorragh?",o:["Drukhari", "Exoditas", "Arlequines", "Ynnari"],a:0,exp:"Los Drukhari, o Eldar Oscuros, viven en Commorragh dentro de la Telara\u00f1a.",extra:"Evitan que Slaanesh devore sus almas aliment\u00e1ndose del dolor de otros, lo que los convierte en una sociedad de piratas, torturadores y arist\u00f3cratas crueles."},
  {t:"m",q:"\u00bfQu\u00e9 red dimensional usan los Aeldari para viajar evitando la Disformidad abierta?",o:["Telara\u00f1a/Webway", "Astronomican", "Cicatrix", "Noosfera"],a:0,exp:"La Telara\u00f1a es una red de t\u00faneles dimensionales usada por los Aeldari.",extra:"Es m\u00e1s segura que la Disformidad, aunque est\u00e1 da\u00f1ada y llena de peligros. El Emperador intent\u00f3 crear un acceso humano a ella."},
  {t:"m",q:"\u00bfQu\u00e9 dios Eldar de la guerra sobrevive fragmentado en avatares?",o:["Khaine", "Cegorach", "Isha", "Asuryan"],a:0,exp:"Khaine, dios Eldar de la guerra, sobrevive como fragmentos encarnados en Avatares de Khaine.",extra:"Los Avatares son despertados en tiempos de guerra mediante rituales sangrientos en los mundos astronave."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n Eldar sigue al dios de la risa?",o:["Arlequines", "Drukhari", "Exoditas", "Corsarios"],a:0,exp:"Los Arlequines sirven a Cegorach, el Dios que R\u00ede.",extra:"Act\u00faan como artistas, guerreros y guardianes de secretos, movi\u00e9ndose por la Telara\u00f1a con objetivos enigm\u00e1ticos."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n Eldar busca despertar al dios de la muerte Ynnead?",o:["Ynnari", "Drukhari", "Arlequines", "Exoditas"],a:0,exp:"Los Ynnari buscan despertar a Ynnead, dios Eldar de la muerte, para derrotar a Slaanesh.",extra:"Su aparici\u00f3n desaf\u00eda divisiones entre Craftworld, Drukhari y otros Aeldari, proponiendo una esperanza peligrosa y radical."},
  {t:"m",q:"\u00bfQu\u00e9 raza xenos es conocida por su grito \u201cWaaagh!\u201d?",o:["Orkos", "T\u2019au", "Tir\u00e1nidos", "Necrones"],a:0,exp:"Los Orkos son famosos por el Waaagh!, tanto grito de guerra como fen\u00f3meno ps\u00edquico colectivo.",extra:"Los Orkos son brutales, c\u00f3micos y aterradores: una especie creada para la guerra que disfruta pelear m\u00e1s que ganar."},
  {t:"m",q:"\u00bfQu\u00e9 dos dioses adoran los Orkos?",o:["Gork y Mork", "Khorne y Nurgle", "Khaine y Cegorach", "Sigmar y Ulric"],a:0,exp:"Los Orkos adoran a Gork y Mork.",extra:"Uno es brutal pero astuto y el otro astuto pero brutal, aunque los Orkos discuten eternamente cu\u00e1l es cu\u00e1l."},
  {t:"m",q:"\u00bfPor qu\u00e9 la tecnolog\u00eda orka funciona de forma extra\u00f1amente eficaz?",o:["Por un campo ps\u00edquico colectivo orko", "Porque es superior al Mechanicus", "Porque usan IA avanzada", "Porque la fabrican los Necrones"],a:0,exp:"La tecnolog\u00eda orka funciona en parte gracias al campo ps\u00edquico colectivo de los Orkos.",extra:"Sus armas y veh\u00edculos son chatarra peligrosa, pero la creencia masiva orka y la intuici\u00f3n de los Mekboyz hacen que funcionen de formas imposibles."},
  {t:"m",q:"\u00bfQu\u00e9 color creen los Orkos que hace que los veh\u00edculos vayan m\u00e1s r\u00e1pido?",o:["Rojo", "Azul", "Verde", "Negro"],a:0,exp:"Los Orkos creen que el rojo hace que las cosas vayan m\u00e1s r\u00e1pido.",extra:"En el tono absurdo de los Orkos, esa creencia puede tener efecto real por su campo ps\u00edquico colectivo."},
  {t:"m",q:"\u00bfQu\u00e9 raza xenos consume biomasa y llega en flotas enjambre?",o:["Tir\u00e1nidos", "Necrones", "T\u2019au", "Aeldari"],a:0,exp:"Los Tir\u00e1nidos son una especie extragal\u00e1ctica que consume biomasa mediante flotas enjambre.",extra:"No conquistan por pol\u00edtica o fe: devoran mundos enteros y reciclan todo material biol\u00f3gico para crear m\u00e1s organismos de guerra."},
  {t:"m",q:"\u00bfQu\u00e9 mente colectiva controla a los Tir\u00e1nidos?",o:["Mente Enjambre", "C\u2019tan", "Etereos", "Norn Queen"],a:0,exp:"La Mente Enjambre coordina a los Tir\u00e1nidos como una inteligencia ps\u00edquica colectiva.",extra:"Las criaturas sin\u00e1pticas transmiten su voluntad. Sin ellas, muchas bioformas tir\u00e1nidas se vuelven instintivas y menos coordinadas."},
  {t:"m",q:"\u00bfQu\u00e9 cultos humanos preparan mundos para la llegada tir\u00e1nida?",o:["Cultos Genestealer", "Cultos del Mechanicus", "Cultos de Khorne", "Cultos de la Ecclesiarqu\u00eda"],a:0,exp:"Los Cultos Genestealer infiltran sociedades humanas antes de la llegada de una flota tir\u00e1nida.",extra:"Se presentan como movimientos religiosos, obreros o familiares, pero en realidad preparan rebeliones que debilitan al planeta antes de ser devorado."},
  {t:"m",q:"\u00bfQu\u00e9 raza antigua despert\u00f3 de mundos tumba tras millones de a\u00f1os?",o:["Necrones", "T\u2019au", "Orkos", "Votann"],a:0,exp:"Los Necrones son una raza ancestral que despert\u00f3 de estasis en mundos tumba.",extra:"Antes fueron los Necrontyr, una especie mortal y enfermiza que acept\u00f3 cuerpos met\u00e1licos inmortales con consecuencias terribles."},
  {t:"m",q:"\u00bfQu\u00e9 entidades estelares enga\u00f1aron a los Necrontyr para la biotransferencia?",o:["C\u2019tan", "Dioses del Caos", "Antiguos", "Ethereals"],a:0,exp:"Los C\u2019tan enga\u00f1aron a los Necrontyr y los transformaron en Necrones mediante biotransferencia.",extra:"Los Necrones ganaron inmortalidad met\u00e1lica, pero perdieron almas y gran parte de su humanidad."},
  {t:"m",q:"\u00bfContra qui\u00e9n lucharon los Necrontyr y los C\u2019tan en la Guerra en el Cielo?",o:["Los Antiguos", "El Imperio", "Los T\u2019au", "Los Squats"],a:0,exp:"La Guerra en el Cielo enfrent\u00f3 a Necrontyr/C\u2019tan contra los Antiguos.",extra:"Fue un conflicto tan antiguo y colosal que molde\u00f3 la galaxia, la Disformidad y posiblemente el origen de varias especies guerreras."},
  {t:"m",q:"\u00bfQu\u00e9 dinast\u00eda necrona es una de las m\u00e1s famosas?",o:["Sautekh", "Ultramar", "Biel-Tan", "Vior\u2019la"],a:0,exp:"La Dinast\u00eda Sautekh es una de las dinast\u00edas necronas m\u00e1s conocidas.",extra:"Est\u00e1 asociada a Imotekh el Se\u00f1or de la Tormenta, uno de los l\u00edderes necrones m\u00e1s ambiciosos y efectivos."},
  {t:"m",q:"\u00bfQu\u00e9 personaje necr\u00f3n es famoso por coleccionar individuos y artefactos en una galer\u00eda?",o:["Trazyn el Infinito", "Imotekh", "Orikan", "Szarekh"],a:0,exp:"Trazyn el Infinito es un se\u00f1or necr\u00f3n obsesionado con coleccionar piezas hist\u00f3ricas.",extra:"Su museo en Solemnace contiene guerreros, reliquias y momentos robados de toda la galaxia, muchas veces con humor negro."},
  {t:"m",q:"\u00bfQui\u00e9n es el Rey Silente de los Necrones?",o:["Szarekh", "Trazyn", "Imotekh", "Orikan"],a:0,exp:"Szarekh, el Rey Silente, fue el l\u00edder que orden\u00f3 la rebeli\u00f3n contra los C\u2019tan y luego se exili\u00f3.",extra:"Su regreso en la era moderna tiene enormes implicaciones para los Necrones y para la amenaza tir\u00e1nida."},
  {t:"m",q:"\u00bfQu\u00e9 joven imperio xenos predica el \u201cBien Supremo\u201d?",o:["T\u2019au", "Orkos", "Necrones", "Drukhari"],a:0,exp:"El Imperio T\u2019au se organiza alrededor de la ideolog\u00eda del Bien Supremo.",extra:"Los T\u2019au son tecnol\u00f3gicamente avanzados, expansionistas y relativamente j\u00f3venes. Su imagen idealista oculta tensiones de control social y propaganda."},
  {t:"m",q:"\u00bfQu\u00e9 casta T\u2019au lidera pol\u00edticamente su sociedad?",o:["Et\u00e9reos", "Fuego", "Tierra", "Agua"],a:0,exp:"Los Et\u00e9reos dirigen la sociedad T\u2019au y son vistos como gu\u00edas espirituales y pol\u00edticos.",extra:"Su influencia sobre las otras castas es misteriosa y a veces inquietante, sugiriendo mecanismos de control m\u00e1s profundos."},
  {t:"m",q:"\u00bfQu\u00e9 casta T\u2019au se especializa en combate?",o:["Casta del Fuego", "Casta del Agua", "Casta del Aire", "Casta de la Tierra"],a:0,exp:"La Casta del Fuego forma los guerreros del Imperio T\u2019au.",extra:"Usan tecnolog\u00eda de disparo avanzada, drones, armaduras de combate y t\u00e1cticas de fuego coordinado."},
  {t:"m",q:"\u00bfQu\u00e9 comandante T\u2019au es famoso por usar t\u00e1cticas agresivas y romper con los Et\u00e9reos?",o:["Farsight", "Shadowsun", "Aun\u2019Va", "Longstrike"],a:0,exp:"Comandante Farsight lidera los Enclaves Farsight y se separa de la autoridad principal T\u2019au.",extra:"Farsight es una figura inc\u00f3moda: h\u00e9roe militar, rebelde pol\u00edtico y portador de una espada xenos misteriosa."},
  {t:"m",q:"\u00bfQu\u00e9 comandante T\u2019au es una estratega leal prominente del imperio?",o:["Shadowsun", "Farsight", "Aun\u2019Shi", "Darkstrider"],a:0,exp:"Comandante Shadowsun es una de las l\u00edderes militares m\u00e1s importantes y leales del Imperio T\u2019au.",extra:"Representa la guerra moderna T\u2019au: sigilo, coordinaci\u00f3n, tecnolog\u00eda y ataques a distancia de precisi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 especie mercenaria suele servir como auxiliares del Imperio T\u2019au?",o:["Kroot", "Orkos", "Eldar", "Squigs"],a:0,exp:"Los Kroot son una especie auxiliar com\u00fan dentro del Imperio T\u2019au.",extra:"Son cazadores y guerreros que absorben rasgos gen\u00e9ticos de lo que comen, una caracter\u00edstica que los hace muy adaptables."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n humana antigua regres\u00f3 como Ligas de Votann?",o:["Kin/Squats", "Men of Iron", "Interex", "Thunder Warriors"],a:0,exp:"Las Ligas de Votann representan a los Kin, una civilizaci\u00f3n abhumana ligada al antiguo concepto de Squats.",extra:"Viven cerca del n\u00facleo gal\u00e1ctico, valoran ancestros, miner\u00eda, ingenier\u00eda y los Votann, inteligencias ancestrales cada vez m\u00e1s saturadas."},
  {t:"m",q:"\u00bfQu\u00e9 son los Votann para los Kin?",o:["N\u00facleos ancestrales de conocimiento e inteligencia", "Dioses del Caos menores", "Titanes mineros", "Armas tir\u00e1nidas"],a:0,exp:"Los Votann son n\u00facleos ancestrales que almacenan conocimiento, cultura y gu\u00eda para las Ligas.",extra:"Son venerados casi como ancestros, pero su antig\u00fcedad y sobrecarga los vuelve lentos, cr\u00edpticos y problem\u00e1ticos."},
  {t:"m",q:"\u00bfQu\u00e9 raza o facci\u00f3n est\u00e1 ligada a la frase \u201cPor el Emperador\u201d?",o:["Imperio de la Humanidad", "T\u2019au", "Necrones", "Aeldari"],a:0,exp:"\u201cPor el Emperador\u201d es una expresi\u00f3n t\u00edpica de devoci\u00f3n imperial.",extra:"La fe imperial es tanto consuelo como herramienta de control. En un universo tan terrible, creer en el Emperador puede mantener unido a un soldado com\u00fan."},
  {t:"m",q:"\u00bfQu\u00e9 era Warhammer Fantasy Battles?",o:["El wargame de fantas\u00eda original de Games Workshop", "Una facci\u00f3n de 40K", "Un videojuego de carreras", "Una novela de ciencia ficci\u00f3n"],a:0,exp:"Warhammer Fantasy Battles fue el wargame de fantas\u00eda cl\u00e1sica de Games Workshop.",extra:"Su mundo mezclaba imperios humanos, elfos, enanos, orcos, skaven, caos y no muertos en un tono oscuro y sat\u00edrico."},
  {t:"m",q:"\u00bfQu\u00e9 evento destruy\u00f3 el mundo de Warhammer Fantasy?",o:["El Fin de los Tiempos", "La Herej\u00eda de Horus", "La Ca\u00edda de Cadia", "La Guerra de la Barba"],a:0,exp:"El Fin de los Tiempos fue el evento apocal\u00edptico que destruy\u00f3 el Viejo Mundo.",extra:"Tras ese final naci\u00f3 Warhammer Age of Sigmar, ambientado en los Reinos Mortales."},
  {t:"m",q:"\u00bfQu\u00e9 dios-h\u00e9roe da nombre a Age of Sigmar?",o:["Sigmar", "Nagash", "Khorne", "Grungni"],a:0,exp:"Sigmar es la figura central de Warhammer Age of Sigmar.",extra:"En Fantasy fue fundador divinizado del Imperio; en Age of Sigmar es un dios que lidera la resistencia contra el Caos desde Azyr."},
  {t:"m",q:"\u00bfQu\u00e9 guerreros celestiales crea Sigmar en Age of Sigmar?",o:["Stormcast Eternals", "Space Marines", "Freeguild", "Custodes"],a:0,exp:"Los Stormcast Eternals son campeones mortales reforjados por Sigmar.",extra:"Son h\u00e9roes devueltos a la guerra una y otra vez, pero cada reforja erosiona algo de su humanidad."},
  {t:"m",q:"\u00bfQu\u00e9 dios de la muerte domina Shyish en Age of Sigmar?",o:["Nagash", "Sigmar", "Teclis", "Grimnir"],a:0,exp:"Nagash es el dios supremo de la muerte y domina Shyish.",extra:"Nagash busca controlar todas las almas y detesta que otros dioses o el Caos le roben lo que considera suyo."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n de no muertos sirve directamente a Nagash como legiones disciplinadas?",o:["Ossiarch Bonereapers", "Orruk Warclans", "Sylvaneth", "Kharadron Overlords"],a:0,exp:"Los Ossiarch Bonereapers son ej\u00e9rcitos de hueso creados para servir a Nagash.",extra:"No son esqueletos comunes: son construcciones militares de almas y huesos, dise\u00f1adas para cobrar diezmos \u00f3seos a civilizaciones enteras."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n vamp\u00edrica gobierna dinast\u00edas de no muertos en Age of Sigmar?",o:["Soulblight Gravelords", "Daughters of Khaine", "Fyreslayers", "Seraphon"],a:0,exp:"Los Soulblight Gravelords son dinast\u00edas vamp\u00edricas y ej\u00e9rcitos de no muertos.",extra:"Herederos espirituales de los Condes Vampiro, combinan aristocracia decadente, necromancia y monstruosidad."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n de elfos oscuros adora a Khaine mediante culto sangriento?",o:["Daughters of Khaine", "Lumineth Realm-lords", "Idoneth Deepkin", "Sylvaneth"],a:0,exp:"Las Daughters of Khaine son cultistas aelfas dedicadas a Khaine.",extra:"Morathi manipula este culto para consolidar su propia divinidad y poder pol\u00edtico."},
  {t:"m",q:"\u00bfQui\u00e9n es Morathi?",o:["Una poderosa hechicera aelfa convertida en diosa", "Una reina enana", "Una general skaven", "Una santa de Sigmar"],a:0,exp:"Morathi es una figura aelfa antigua, manipuladora y ambiciosa, ligada al culto de Khaine.",extra:"En Age of Sigmar alcanza divinidad, convirti\u00e9ndose en Morathi-Khaine y alterando el equilibrio entre los dioses aelfos."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n aelfa vive bajo el mar y roba almas?",o:["Idoneth Deepkin", "Lumineth Realm-lords", "Daughters of Khaine", "Cities of Sigmar"],a:0,exp:"Los Idoneth Deepkin viven en reinos submarinos y roban almas para sobrevivir.",extra:"Son descendientes imperfectos de almas rescatadas de Slaanesh, con una maldici\u00f3n espiritual que los obliga a atacar asentamientos costeros."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n aelfa est\u00e1 asociada a Hysh y a la luz?",o:["Lumineth Realm-lords", "Idoneth Deepkin", "Sylvaneth", "Daughters of Khaine"],a:0,exp:"Los Lumineth Realm-lords son aelfos de Hysh, el Reino de la Luz.",extra:"Buscan equilibrio, iluminaci\u00f3n y perfecci\u00f3n, pero tambi\u00e9n arrastran orgullo y errores que casi destruyeron su civilizaci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n forestal est\u00e1 ligada a Alarielle?",o:["Sylvaneth", "Seraphon", "Fyreslayers", "Beasts of Chaos"],a:0,exp:"Los Sylvaneth son esp\u00edritus arb\u00f3reos y guerreros del bosque ligados a Alarielle.",extra:"Defienden los ciclos de vida natural, especialmente en Ghyran, contra la corrupci\u00f3n de Nurgle y otros invasores."},
  {t:"m",q:"\u00bfQu\u00e9 diosa representa la vida en Age of Sigmar?",o:["Alarielle", "Morathi", "Isha", "Valkia"],a:0,exp:"Alarielle es la diosa de la vida y figura central de los Sylvaneth.",extra:"Su guerra contra Nurgle en Ghyran es una lucha entre crecimiento vivo y putrefacci\u00f3n corrupta."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n duardin mercantil navega por los cielos en barcos a\u00e9reos?",o:["Kharadron Overlords", "Fyreslayers", "Dispossessed", "Ironjawz"],a:0,exp:"Los Kharadron Overlords son duardin capitalistas y tecnol\u00f3gicamente avanzados que viajan en flotas a\u00e9reas.",extra:"Su sociedad se basa en c\u00f3digos comerciales, aether-gold, armas de fuego y pragmatismo empresarial extremo."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n duardin mercenaria busca ur-gold?",o:["Fyreslayers", "Kharadron Overlords", "Stormcast", "Ossiarch"],a:0,exp:"Los Fyreslayers son duardin mercenarios obsesionados con el ur-gold.",extra:"Creen que el ur-gold contiene fragmentos de su dios Grimnir, por eso lo incrustan en su carne como runas de poder."},
  {t:"m",q:"\u00bfQu\u00e9 raza reptiliana de Age of Sigmar hereda el legado de los Hombres Lagarto?",o:["Seraphon", "Skaven", "Orruks", "Flesh-eater Courts"],a:0,exp:"Los Seraphon son la evoluci\u00f3n del concepto de Hombres Lagarto en Age of Sigmar.",extra:"Sirven al Gran Plan de los Ancestrales y combinan dinosaurios, magia celeste y civilizaci\u00f3n mesoamericana fant\u00e1stica."},
  {t:"m",q:"\u00bfQu\u00e9 raza de hombres rata es famosa por traici\u00f3n, plagas e ingenier\u00eda peligrosa?",o:["Skaven", "Goblins", "Beastmen", "Ghouls"],a:0,exp:"Los Skaven son hombres rata ca\u00f3ticos, paranoicos y traicioneros.",extra:"Son una de las facciones m\u00e1s queridas por su mezcla de horror y humor: todos se traicionan, todos mienten y aun as\u00ed casi conquistan el mundo."},
  {t:"m",q:"\u00bfQu\u00e9 sustancia corrupta usan los Skaven como fuente de poder?",o:["Piedra bruja", "Aether-gold", "Ur-gold", "Noctilith"],a:0,exp:"La piedra bruja es una sustancia m\u00e1gica y corrupta esencial para los Skaven.",extra:"La usan en armas, motores, hechicer\u00eda y experimentos, casi siempre con resultados inestables y catastr\u00f3ficos."},
  {t:"m",q:"\u00bfQu\u00e9 dios veneran los Skaven?",o:["La Gran Rata Cornuda", "Khorne", "Nagash", "Gorkamorka"],a:0,exp:"Los Skaven adoran a la Gran Rata Cornuda.",extra:"En Age of Sigmar, esta entidad asciende como un dios del Caos, reflejando la magnitud de la amenaza skaven."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n orruk representa la brutalidad pesada y armaduras enormes?",o:["Ironjawz", "Kruleboyz", "Bonesplitterz", "Gloomspite Gitz"],a:0,exp:"Los Ironjawz son orruks enormes, violentos y cubiertos de armaduras pesadas.",extra:"Su filosof\u00eda es simple: buscar la pelea m\u00e1s grande posible y aplastarla con fuerza directa."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n orruk destaca por astucia, trampas y crueldad pantanosa?",o:["Kruleboyz", "Ironjawz", "Bonesplitterz", "Fyreslayers"],a:0,exp:"Los Kruleboyz son orruks m\u00e1s astutos, crueles y tramposos.",extra:"A diferencia de la brutalidad frontal de los Ironjawz, prefieren emboscadas, venenos, intimidaci\u00f3n y monstruos de pantano."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n goblin nocturna est\u00e1 ligada a hongos, cuevas y la Luna Mala?",o:["Gloomspite Gitz", "Kharadron", "Cities of Sigmar", "Seraphon"],a:0,exp:"Los Gloomspite Gitz re\u00fanen goblins cavernarios, squigs, trolls y fan\u00e1ticos de la Luna Mala.",extra:"Son ca\u00f3ticos, alucinados y peligrosamente c\u00f3micos, con una est\u00e9tica de hongos, lunas siniestras y hordas subterr\u00e1neas."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n de can\u00edbales no muertos cree vivir en una corte noble por delirio m\u00e1gico?",o:["Flesh-eater Courts", "Soulblight Gravelords", "Ossiarch Bonereapers", "Nighthaunt"],a:0,exp:"Las Flesh-eater Courts son necr\u00f3fagos que se perciben a s\u00ed mismos como caballeros y nobles por una maldici\u00f3n delirante.",extra:"Su horror funciona por contraste: el lector ve monstruos comiendo cad\u00e1veres, pero ellos creen vivir gestas heroicas y banquetes refinados."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n fantasmal sirve a Nagash con esp\u00edritus atormentados?",o:["Nighthaunt", "Seraphon", "Skaven", "Idoneth"],a:0,exp:"Los Nighthaunt son espectros castigados y esclavizados por Nagash.",extra:"Cada esp\u00edritu suele sufrir una condena ir\u00f3nica ligada a su vida anterior, convertida en arma de terror."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n humana multirracial representa ciudades libres en Age of Sigmar?",o:["Cities of Sigmar", "Stormcast Eternals", "Freeguild only", "Dawnbringers"],a:0,exp:"Cities of Sigmar representa ciudades mortales de humanos, duardin y aelfos bajo el orden de Sigmar.",extra:"Son la cara m\u00e1s humana de Age of Sigmar: soldados, gremios, colonos y civiles intentando sobrevivir entre dioses y monstruos."},
  {t:"m",q:"\u00bfQu\u00e9 mundo era el principal escenario de Warhammer Fantasy?",o:["El Viejo Mundo", "Terra", "Azyr", "Commorragh"],a:0,exp:"El Viejo Mundo era el escenario central de Warhammer Fantasy.",extra:"Inclu\u00eda el Imperio, Bretonia, Kislev, los Reinos Enanos, Sylvania, las Tierras del Caos y muchas otras regiones."},
  {t:"m",q:"\u00bfQu\u00e9 naci\u00f3n humana de Fantasy estaba inspirada en el Sacro Imperio Romano Germ\u00e1nico?",o:["El Imperio", "Bretonia", "Kislev", "Estalia"],a:0,exp:"El Imperio de Warhammer Fantasy estaba inspirado en el Sacro Imperio Romano Germ\u00e1nico.",extra:"Combinaba p\u00f3lvora, religi\u00f3n sigmarita, provincias electorales, magia colegiada y monstruos acechando en bosques oscuros."},
  {t:"m",q:"\u00bfQui\u00e9n fue Sigmar en Warhammer Fantasy?",o:["Fundador del Imperio y dios patr\u00f3n", "Rey de los Enanos", "Primer vampiro", "Se\u00f1or del Caos"],a:0,exp:"Sigmar fue el fundador del Imperio y luego venerado como dios.",extra:"Su martillo Ghal Maraz se volvi\u00f3 uno de los s\u00edmbolos m\u00e1s importantes del orden humano."},
  {t:"m",q:"\u00bfQu\u00e9 arma legendaria est\u00e1 asociada a Sigmar?",o:["Ghal Maraz", "Aenarion", "Slayer of Kings", "Widowmaker"],a:0,exp:"Ghal Maraz es el martillo legendario de Sigmar.",extra:"En Fantasy fue s\u00edmbolo imperial; en Age of Sigmar, sigue siendo un emblema central del poder de Sigmar."},
  {t:"m",q:"\u00bfQu\u00e9 naci\u00f3n humana de Fantasy est\u00e1 inspirada en caballer\u00eda art\u00farica y feudalismo?",o:["Bretonia", "Kislev", "El Imperio", "Tilea"],a:0,exp:"Bretonia est\u00e1 inspirada en caballeros art\u00faricos, feudalismo y culto a la Dama del Lago.",extra:"Su ideal caballeresco convive con desigualdad brutal entre nobles y campesinos, un contraste t\u00edpico del tono de Warhammer."},
  {t:"m",q:"\u00bfQu\u00e9 regi\u00f3n humana de Fantasy est\u00e1 inspirada en Europa oriental y lucha contra el Caos del norte?",o:["Kislev", "Bretonia", "Estalia", "Marienburgo"],a:0,exp:"Kislev es una naci\u00f3n fronteriza contra las invasiones del Caos.",extra:"Su cultura mezcla hielo, caballer\u00eda, osos, magia helada y resistencia desesperada contra las hordas del norte."},
  {t:"m",q:"\u00bfQu\u00e9 raza de Fantasy guarda agravios en libros sagrados?",o:["Enanos", "Altos Elfos", "Orcos", "Skaven"],a:0,exp:"Los Enanos registran ofensas en el Gran Libro de los Agravios.",extra:"La cultura enana se basa en honor, memoria, artesan\u00eda y rencores que pueden durar siglos."},
  {t:"m",q:"\u00bfQu\u00e9 guerra hist\u00f3rica enfrent\u00f3 a Enanos y Altos Elfos en Fantasy?",o:["Guerra de la Barba", "Fin de los Tiempos", "Guerra de los Cielos", "Cruzada de Errantry"],a:0,exp:"La Guerra de la Barba enfrent\u00f3 a Enanos y Altos Elfos, devastando a ambas civilizaciones.",extra:"Fue causada por orgullo, manipulaci\u00f3n de los Elfos Oscuros y una escalada de insultos imposibles de perdonar."},
  {t:"m",q:"\u00bfQu\u00e9 isla-reino era hogar de los Altos Elfos?",o:["Ulthuan", "Naggaroth", "Lustria", "Sylvania"],a:0,exp:"Ulthuan era el reino insular de los Altos Elfos.",extra:"Su v\u00f3rtice m\u00e1gico manten\u00eda a raya al Caos, convirti\u00e9ndolo en uno de los lugares m\u00e1s importantes del mundo de Fantasy."},
  {t:"m",q:"\u00bfQu\u00e9 tierra era hogar de los Elfos Oscuros?",o:["Naggaroth", "Ulthuan", "Athel Loren", "Nehekhara"],a:0,exp:"Naggaroth era la tierra helada y cruel de los Elfos Oscuros.",extra:"Gobernados por Malekith y Morathi, los Druchii mezclaban esclavitud, pirater\u00eda, magia oscura y odio eterno hacia Ulthuan."},
  {t:"m",q:"\u00bfQui\u00e9n fue Malekith en Warhammer Fantasy?",o:["Rey Brujo de los Elfos Oscuros", "Emperador humano", "Primer vampiro", "Se\u00f1or enano"],a:0,exp:"Malekith fue el Rey Brujo de los Elfos Oscuros.",extra:"Su historia nace de una disputa sucesoria \u00e9lfica y de su fracaso al intentar reclamar el trono de Ulthuan."},
  {t:"m",q:"\u00bfQu\u00e9 bosque es hogar de los Elfos Silvanos?",o:["Athel Loren", "Naggaroth", "Ulthuan", "Lustria"],a:0,exp:"Athel Loren es el bosque m\u00e1gico de los Elfos Silvanos.",extra:"All\u00ed los elfos conviven con esp\u00edritus arb\u00f3reos, en una alianza peligrosa entre civilizaci\u00f3n \u00e9lfica y voluntad salvaje del bosque."},
  {t:"m",q:"\u00bfQu\u00e9 regi\u00f3n selv\u00e1tica era hogar de los Hombres Lagarto?",o:["Lustria", "Kislev", "Sylvania", "Norsca"],a:0,exp:"Lustria era la gran regi\u00f3n selv\u00e1tica de los Hombres Lagarto.",extra:"Sus ciudades templo guardaban planes de los Ancestrales y eran defendidas por saurios, eslizones y enormes dinosaurios."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00edderes momificados gobiernan Nehekhara?",o:["Reyes Funerarios", "Condes Vampiro", "Se\u00f1ores Skaven", "Archimagos Altos Elfos"],a:0,exp:"Los Reyes Funerarios gobiernan Nehekhara como monarcas no muertos.",extra:"A diferencia de los vampiros, no se ven como monstruos malditos, sino como reyes leg\u00edtimos despertados en un imperio arruinado."},
  {t:"m",q:"\u00bfQui\u00e9n fue Nagash en Warhammer Fantasy?",o:["El gran nigromante y padre de la no muerte", "Primer emperador humano", "Rey de Bretonia", "Dios orco"],a:0,exp:"Nagash fue el mayor nigromante de Fantasy y figura central en el origen de la no muerte.",extra:"Su ambici\u00f3n por dominar la muerte lo convierte en una de las entidades m\u00e1s peligrosas de todo Warhammer."},
  {t:"m",q:"\u00bfQu\u00e9 regi\u00f3n est\u00e1 asociada a los Condes Vampiro?",o:["Sylvania", "Kislev", "Ulthuan", "Lustria"],a:0,exp:"Sylvania es la tierra oscura asociada a los Condes Vampiro.",extra:"Es una provincia maldita de bosques negros, castillos g\u00f3ticos, cementerios y nobles vamp\u00edricos."},
  {t:"m",q:"\u00bfQu\u00e9 familia vamp\u00edrica es central en Sylvania?",o:["Von Carstein", "Harkon", "Lahmian", "Strigoi"],a:0,exp:"Los von Carstein son la dinast\u00eda vamp\u00edrica m\u00e1s famosa de Sylvania.",extra:"Vlad, Isabella y Mannfred von Carstein son figuras clave de las Guerras Vamp\u00edricas y del Fin de los Tiempos."},
  {t:"m",q:"\u00bfQu\u00e9 raza ca\u00f3tica de Fantasy vive bajo ciudades y t\u00faneles?",o:["Skaven", "Orcos", "Hombres Bestia", "Necrones"],a:0,exp:"Los Skaven viven en el Subimperio, una red de t\u00faneles y ciudades bajo el mundo.",extra:"La mayor\u00eda de naciones niega o subestima su existencia, lo que facilita que los Skaven conspiren bajo sus pies."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad skaven es la capital del Subimperio?",o:["Skavenblight", "Altdorf", "Naggarond", "Karak Ocho Picos"],a:0,exp:"Skavenblight es la capital pestilente de los Skaven.",extra:"Es un centro de corrupci\u00f3n, pol\u00edtica traicionera, ingenier\u00eda peligrosa y adoraci\u00f3n a la Gran Rata Cornuda."},
  {t:"m",q:"\u00bfQu\u00e9 fortaleza enana es disputada por Enanos, Skaven y Goblins Nocturnos?",o:["Karak Ocho Picos", "Karak Kadrin", "Altdorf", "Middenheim"],a:0,exp:"Karak Ocho Picos es una antigua fortaleza enana disputada por varias facciones.",extra:"Su lucha simboliza la decadencia enana y la imposibilidad de recuperar f\u00e1cilmente glorias perdidas."},
  {t:"m",q:"\u00bfQu\u00e9 l\u00edder goblin nocturno est\u00e1 asociado a Karak Ocho Picos?",o:["Skarsnik", "Grimgor", "Grom", "Azhag"],a:0,exp:"Skarsnik es un astuto caudillo goblin nocturno ligado a Karak Ocho Picos.",extra:"A diferencia de los orcos m\u00e1s directos, Skarsnik destaca por trampas, crueldad y una inteligencia peligrosa."},
  {t:"m",q:"\u00bfQu\u00e9 orco negro es uno de los caudillos m\u00e1s famosos de Fantasy?",o:["Grimgor Ironhide", "Skarsnik", "Grom el Panzudo", "Wurrzag"],a:0,exp:"Grimgor Ironhide es uno de los orcos negros m\u00e1s temidos.",extra:"Representa la fuerza bruta orca en su forma m\u00e1s pura: quiere pelear contra el enemigo m\u00e1s fuerte disponible."},
  {t:"m",q:"\u00bfQu\u00e9 campe\u00f3n del Caos fue elegido como gran se\u00f1or del Fin de los Tiempos?",o:["Archaon", "Kharn", "Abaddon", "Aekold"],a:0,exp:"Archaon el Elegido fue el gran campe\u00f3n del Caos durante el Fin de los Tiempos.",extra:"Archaon busca destruir el mundo no como sirviente simple, sino como alguien que odia a los dioses y al destino que le impusieron."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00edtulo tiene Archaon?",o:["El Elegido Eterno", "Rey Silente", "Se\u00f1or de Macragge", "Gran Nigromante"],a:0,exp:"Archaon es conocido como el Elegido Eterno.",extra:"Es el campe\u00f3n supremo de los Dioses del Caos en Fantasy y Age of Sigmar, aunque su relaci\u00f3n con ellos est\u00e1 llena de desprecio."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n representa hombres y bestias mutadas por el Caos en bosques y tierras salvajes?",o:["Hombres Bestia", "Bretonianos", "Lumineth", "T\u2019au"],a:0,exp:"Los Hombres Bestia son criaturas mutantes consagradas al Caos y al salvajismo primordial.",extra:"Ven la civilizaci\u00f3n como una mentira d\u00e9bil que debe ser arrasada para devolver el mundo a una brutalidad natural."},
  {t:"m",q:"\u00bfQu\u00e9 juego deportivo par\u00f3dico mezcla Warhammer Fantasy con f\u00fatbol americano?",o:["Blood Bowl", "Mordheim", "Necromunda", "Warcry"],a:0,exp:"Blood Bowl mezcla fantas\u00eda de Warhammer con f\u00fatbol americano violento y humor negro.",extra:"Equipos de humanos, orcos, enanos, elfos, no muertos y skaven compiten en partidos donde hacer trampa y lesionar rivales es parte del encanto."},
  {t:"m",q:"\u00bfQu\u00e9 juego se ambienta en una ciudad destruida por piedra bruja?",o:["Mordheim", "Blood Bowl", "Battlefleet Gothic", "Kill Team"],a:0,exp:"Mordheim se ambienta en una ciudad arruinada por la ca\u00edda de un cometa de piedra bruja.",extra:"Bandas rivales exploran ruinas buscando riqueza, mutaciones y muerte en un entorno oscuro de escaramuzas."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Warhammer 40K se centra en combates de bandas dentro de colmenas?",o:["Necromunda", "Mordheim", "Blood Bowl", "Warcry"],a:0,exp:"Necromunda se centra en guerras de bandas en ciudades colmena imperiales.",extra:"Muestra el lado callejero y criminal del Imperio: casas industriales, pandillas, mutantes, cazarrecompensas y contaminaci\u00f3n extrema."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 40K se centra en escaramuzas de equipos peque\u00f1os?",o:["Kill Team", "Adeptus Titanicus", "Battlefleet Gothic", "Epic"],a:0,exp:"Kill Team representa operaciones de escuadras peque\u00f1as en el universo 40K.",extra:"Permite contar historias de comandos, infiltraci\u00f3n y objetivos t\u00e1cticos sin desplegar ej\u00e9rcitos completos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 40K se centra en batallas de naves espaciales?",o:["Battlefleet Gothic", "Necromunda", "Blood Bowl", "Warcry"],a:0,exp:"Battlefleet Gothic se centra en combates navales espaciales entre flotas.",extra:"Representa otra escala de guerra en 40K: cruceros, acorazados, torpedos, abordajes y catedrales volando por el vac\u00edo."},
  {t:"m",q:"\u00bfQu\u00e9 ciudad colmena es el escenario principal de Necromunda?",o:["Necromunda/Primus Hive", "Cadia", "Macragge", "Commorragh"],a:0,exp:"Necromunda es un mundo colmena, y muchas historias se centran en sus inmensas colmenas industriales.",extra:"Sus niveles inferiores son un infierno de pandillas, qu\u00edmicos, ruinas, mutantes y econom\u00edas criminales."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n de Warhammer 40K est\u00e1 formada por cultistas y Marines traidores al servicio de los dioses oscuros?",o:["Caos", "Astra Militarum", "Aeldari", "T\u2019au"],a:0,exp:"Las fuerzas del Caos incluyen Marines traidores, demonios, cultistas y mundos corruptos.",extra:"El Caos es una amenaza externa e interna: puede invadir con ej\u00e9rcitos o pudrir una sociedad desde sus deseos, miedos y ambiciones."},
  {t:"m",q:"\u00bfQu\u00e9 Marines del Caos no se dedican a un dios \u00fanico, sino al Caos en conjunto?",o:["Legi\u00f3n Negra", "Devoradores de Mundos", "Guardia de la Muerte", "Mil Hijos"],a:0,exp:"La Legi\u00f3n Negra, liderada por Abaddon, re\u00fane traidores de m\u00faltiples or\u00edgenes bajo el Caos Indiviso.",extra:"Naci\u00f3 de los restos de los Hijos de Horus y otros renegados, rechazando vivir solo a la sombra del fracaso de Horus."},
  {t:"m",q:"\u00bfQu\u00e9 eran los Hijos de Horus antes de cambiar de nombre?",o:["Lobos Lunares", "Ultramarines", "Portadores de la Palabra", "Pu\u00f1os Imperiales"],a:0,exp:"La legi\u00f3n de Horus se llam\u00f3 originalmente Lobos Lunares, luego Hijos de Horus.",extra:"Tras la Herej\u00eda y la muerte de Horus, Abaddon repudi\u00f3 esa identidad y fund\u00f3 la Legi\u00f3n Negra."},
  {t:"m",q:"\u00bfQu\u00e9 mundo de los Ultramarines es capital de Ultramar?",o:["Macragge", "Baal", "Fenris", "Caliban"],a:0,exp:"Macragge es el mundo natal de los Ultramarines y capital del reino de Ultramar.",extra:"Ultramar es un conjunto de mundos relativamente bien administrados, lo que contrasta con la miseria com\u00fan en gran parte del Imperio."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal de los \u00c1ngeles Sangrientos fue atacado por los Tir\u00e1nidos?",o:["Baal", "Macragge", "Fenris", "Nocturne"],a:0,exp:"Baal, mundo de los \u00c1ngeles Sangrientos, sufri\u00f3 una invasi\u00f3n devastadora tir\u00e1nida.",extra:"La Devastaci\u00f3n de Baal casi destruy\u00f3 al cap\u00edtulo y sus sucesores, hasta la llegada de refuerzos imperiales y Primaris."},
  {t:"m",q:"\u00bfQu\u00e9 cap\u00edtulo es famoso por su est\u00e9tica mon\u00e1stica, secretos y t\u00fanicas?",o:["\u00c1ngeles Oscuros", "Cicatrices Blancas", "Salamandras", "Manos de Hierro"],a:0,exp:"Los \u00c1ngeles Oscuros combinan caballer\u00eda mon\u00e1stica, secretos y cacer\u00eda obsesiva de los Ca\u00eddos.",extra:"Su fortaleza-monasterio, La Roca, es un fragmento de su mundo destruido, Caliban."},
  {t:"m",q:"\u00bfC\u00f3mo se llama la fortaleza m\u00f3vil de los \u00c1ngeles Oscuros?",o:["La Roca", "La Falange", "Macragge\u2019s Honour", "Vengeful Spirit"],a:0,exp:"La Roca es la fortaleza-monasterio de los \u00c1ngeles Oscuros.",extra:"Es un fragmento del planeta Caliban, destruido durante la tragedia interna del cap\u00edtulo."},
  {t:"m",q:"\u00bfQu\u00e9 nave fue el buque insignia de Horus?",o:["Vengeful Spirit", "Macragge\u2019s Honour", "Phalanx", "Eternal Crusader"],a:0,exp:"El Vengeful Spirit fue la nave insignia de Horus.",extra:"All\u00ed ocurri\u00f3 el duelo final entre el Emperador, Sanguinius y Horus durante el cl\u00edmax de la Herej\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 fortaleza-nave est\u00e1 asociada a los Pu\u00f1os Imperiales?",o:["Phalanx", "Vengeful Spirit", "Eternal Crusader", "Rock"],a:0,exp:"Phalanx es la gigantesca fortaleza-nave de los Pu\u00f1os Imperiales.",extra:"Es una de las mayores estructuras militares m\u00f3viles del Imperio y s\u00edmbolo del legado de Rogal Dorn."},
  {t:"m",q:"\u00bfQu\u00e9 nave est\u00e1 asociada a los Templarios Negros?",o:["Eternal Crusader", "Phalanx", "Vengeful Spirit", "Invincible Reason"],a:0,exp:"El Eternal Crusader es la fortaleza-nave de los Templarios Negros.",extra:"Desde ella coordinan cruzadas interminables contra herejes, xenos y enemigos del Emperador."},
  {t:"m",q:"\u00bfQu\u00e9 personaje es el gran comisario h\u00e9roe de Ciaphas Cain?",o:["Ciaphas Cain", "Gaunt", "Yarrick", "Creed"],a:0,exp:"Ciaphas Cain es un comisario imperial famoso por sobrevivir a situaciones imposibles.",extra:"Sus historias mezclan hero\u00edsmo real con humor, autopreservaci\u00f3n y una reputaci\u00f3n mucho m\u00e1s gloriosa de lo que \u00e9l cree merecer."},
  {t:"m",q:"\u00bfQu\u00e9 comisario est\u00e1 asociado a la defensa de Armageddon contra Ghazghkull?",o:["Sebastian Yarrick", "Ciaphas Cain", "Ibram Gaunt", "Ursarkar Creed"],a:0,exp:"Sebastian Yarrick es el comisario legendario asociado a las guerras de Armageddon.",extra:"Su rivalidad con Ghazghkull Thraka es una de las relaciones enemigo-respeto m\u00e1s famosas del lore imperial y orko."},
  {t:"m",q:"\u00bfQu\u00e9 caudillo orko lider\u00f3 enormes Waaagh! contra Armageddon?",o:["Ghazghkull Thraka", "Grimgor", "Skarsnik", "Tuska"],a:0,exp:"Ghazghkull Mag Uruk Thraka lider\u00f3 grandes invasiones orkas contra Armageddon.",extra:"Es visto por muchos Orkos como profeta de Gork y Mork, capaz de unir hordas gigantescas bajo una sola guerra."},
  {t:"m",q:"\u00bfQu\u00e9 mundo imperial fue escenario de guerras masivas contra Orkos?",o:["Armageddon", "Baal", "Fenris", "Prospero"],a:0,exp:"Armageddon fue escenario de guerras colosales contra invasiones orkas.",extra:"Tambi\u00e9n tiene un pasado oscuro ligado a Angron y la Primera Guerra de Armageddon, que el Imperio intent\u00f3 ocultar."},
  {t:"m",q:"\u00bfQu\u00e9 mundo fue destruido durante la censura imperial tras Angron en Armageddon?",o:["No fue destruido; se purg\u00f3 y reeduc\u00f3 poblaci\u00f3n y combatientes", "Macragge", "Mars", "Cadia"],a:0,exp:"Tras la Primera Guerra de Armageddon, el Imperio ocult\u00f3 la presencia demon\u00edaca mediante purgas, campos y reubicaciones.",extra:"Este tipo de reacci\u00f3n muestra el horror del Imperio: incluso sobrevivir a una invasi\u00f3n demon\u00edaca puede condenarte por saber demasiado."},
  {t:"m",q:"\u00bfQu\u00e9 planeta fue el mundo de Magnus y los Mil Hijos antes de su destrucci\u00f3n?",o:["Prospero", "Fenris", "Colchis", "Barbarus"],a:0,exp:"Prospero fue el mundo de Magnus el Rojo y los Mil Hijos.",extra:"Fue arrasado por los Lobos Espaciales durante la Quema de Prospero, uno de los momentos m\u00e1s tr\u00e1gicos antes de la Herej\u00eda abierta."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Mortarion?",o:["Barbarus", "Nuceria", "Chemos", "Olympia"],a:0,exp:"Barbarus fue el mundo natal de Mortarion.",extra:"Era un planeta t\u00f3xico gobernado por se\u00f1ores xenos o mutantes en fortalezas de niebla venenosa, moldeando el odio de Mortarion hacia tiranos y brujos."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Angron?",o:["Nuceria", "Barbarus", "Chemos", "Colchis"],a:0,exp:"Angron fue encontrado en Nuceria.",extra:"All\u00ed fue esclavizado como gladiador e implantado con los Clavos del Carnicero, trauma que defini\u00f3 toda su existencia."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Lorgar?",o:["Colchis", "Cthonia", "Olympia", "Caliban"],a:0,exp:"Colchis fue el mundo religioso donde creci\u00f3 Lorgar.",extra:"Su cultura teocr\u00e1tica influy\u00f3 en su necesidad de adorar al Emperador y luego a los dioses del Caos."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Perturabo?",o:["Olympia", "Nocturne", "Deliverance", "Baal"],a:0,exp:"Perturabo fue criado en Olympia.",extra:"Su relaci\u00f3n amarga con su mundo y su papel como herramienta de guerra alimentaron el resentimiento que lo llev\u00f3 a la traici\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Fulgrim?",o:["Chemos", "Prospero", "Nuceria", "Fenris"],a:0,exp:"Fulgrim creci\u00f3 en Chemos.",extra:"Transform\u00f3 un mundo industrial decadente mediante eficiencia y perfeccionismo, rasgos que luego se corromper\u00edan en obsesi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Konrad Curze?",o:["Nostramo", "Caliban", "Cthonia", "Barbarus"],a:0,exp:"Konrad Curze creci\u00f3 en Nostramo, un mundo criminal y oscuro.",extra:"Nostramo molde\u00f3 su creencia de que solo el terror pod\u00eda imponer orden."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Horus?",o:["Cthonia", "Macragge", "Caliban", "Baal"],a:0,exp:"Horus fue asociado a Cthonia, un mundo minero y brutal cercano a Terra.",extra:"La cultura cthoniana influy\u00f3 en el car\u00e1cter de los Lobos Lunares y su hermandad guerrera."},
  {t:"m",q:"\u00bfQu\u00e9 mundo natal ten\u00eda Lion El Jonson?",o:["Caliban", "Macragge", "Fenris", "Nocturne"],a:0,exp:"Lion El Jonson creci\u00f3 en Caliban.",extra:"Caliban era un mundo de bosques oscuros, \u00f3rdenes caballerescas y bestias monstruosas. Su destrucci\u00f3n marc\u00f3 el nacimiento del secreto de los Ca\u00eddos."},
  {t:"m",q:"\u00bfQu\u00e9 primarca fue conocido por su compasi\u00f3n hacia civiles m\u00e1s que la mayor\u00eda?",o:["Vulkan", "Angron", "Perturabo", "Curze"],a:0,exp:"Vulkan y sus Salamandras son famosos por valorar la protecci\u00f3n de civiles humanos.",extra:"En un universo tan brutal, esa humanidad relativa hace que los Salamandras destaquen dentro del Imperio."},
  {t:"m",q:"\u00bfQu\u00e9 primarca era perpetuo, capaz de regresar de la muerte?",o:["Vulkan", "Ferrus Manus", "Sanguinius", "Horus"],a:0,exp:"Vulkan es un perpetuo, capaz de volver de la muerte.",extra:"Su inmortalidad no lo libra del sufrimiento. De hecho, muchas historias exploran cu\u00e1nto puede romper a alguien morir una y otra vez."},
  {t:"m",q:"\u00bfQu\u00e9 primarca muri\u00f3 decapitado en Isstvan V?",o:["Ferrus Manus", "Vulkan", "Corvus Corax", "Fulgrim"],a:0,exp:"Ferrus Manus fue asesinado por Fulgrim durante la Masacre de Isstvan V.",extra:"Su muerte temprana traumatiz\u00f3 a las Manos de Hierro y simboliz\u00f3 la ruptura definitiva entre hermanos."},
  {t:"m",q:"\u00bfQu\u00e9 batalla revel\u00f3 plenamente la traici\u00f3n de varias legiones en la Herej\u00eda?",o:["Masacre de Isstvan V", "Ca\u00edda de Cadia", "Batalla de Macragge", "Cruzada Damocles"],a:0,exp:"La Masacre de Isstvan V revel\u00f3 la traici\u00f3n de legiones que fing\u00edan ser leales.",extra:"Las Legiones Destrozadas, como Manos de Hierro, Salamandras y Guardia del Cuervo, sufrieron p\u00e9rdidas devastadoras."},
  {t:"m",q:"\u00bfQu\u00e9 tres legiones leales fueron casi destruidas en Isstvan V?",o:["Manos de Hierro, Salamandras y Guardia del Cuervo", "Ultramarines, Lobos Espaciales y \u00c1ngeles Oscuros", "Pu\u00f1os Imperiales, Cicatrices Blancas y \u00c1ngeles Sangrientos", "Custodes, Grey Knights y Sororitas"],a:0,exp:"Manos de Hierro, Salamandras y Guardia del Cuervo fueron conocidas como las Legiones Destrozadas tras Isstvan V.",extra:"Su destrucci\u00f3n temprana limit\u00f3 enormemente la respuesta lealista durante la Herej\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 fue el Asedio de Terra?",o:["El ataque final de Horus contra el Palacio Imperial", "La invasi\u00f3n tir\u00e1nida de Baal", "La ca\u00edda de Cadia", "La guerra contra los T\u2019au"],a:0,exp:"El Asedio de Terra fue el ataque culminante de las fuerzas traidoras contra el Palacio Imperial.",extra:"All\u00ed murieron Sanguinius y Horus, y el Emperador qued\u00f3 condenado al Trono Dorado."},
  {t:"m",q:"\u00bfQui\u00e9n se sacrific\u00f3 enfrentando a Horus antes del Emperador?",o:["Sanguinius", "Rogal Dorn", "Malcador", "Vulkan"],a:0,exp:"Sanguinius enfrent\u00f3 a Horus y muri\u00f3 antes del duelo final del Emperador.",extra:"Su muerte a\u00f1ade una dimensi\u00f3n m\u00edtica y tr\u00e1gica a la batalla final, especialmente para los \u00c1ngeles Sangrientos."},
  {t:"m",q:"\u00bfQui\u00e9n ocup\u00f3 temporalmente el Trono Dorado durante el duelo del Emperador?",o:["Malcador el Sigilita", "Rogal Dorn", "Magnus", "Valdor"],a:0,exp:"Malcador ocup\u00f3 el Trono Dorado para permitir que el Emperador enfrentara a Horus.",extra:"El esfuerzo consumi\u00f3 su vida, convirti\u00e9ndolo en uno de los sacrificios m\u00e1s importantes de la Herej\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 facci\u00f3n imperial fue creada originalmente para acompa\u00f1ar a los Custodes contra ps\u00edquicos?",o:["Hermanas del Silencio", "Adepta Sororitas", "Arbites", "Inquisici\u00f3n"],a:0,exp:"Las Hermanas del Silencio son blanks entrenadas para combatir amenazas ps\u00edquicas.",extra:"Durante la Gran Cruzada y la Herej\u00eda formaban, junto a los Custodes, las Garras del Emperador."},
  {t:"m",q:"\u00bfQu\u00e9 son los Thunder Warriors?",o:["Guerreros proto-Astartes usados por el Emperador en la Unificaci\u00f3n de Terra", "T\u2019au con armadura pesada", "Orkos de \u00e9lite", "Necrones defectuosos"],a:0,exp:"Los Thunder Warriors fueron guerreros gen\u00e9ticamente modificados anteriores a los Marines Espaciales.",extra:"Ayudaron al Emperador a conquistar Terra, pero eran inestables y fueron eliminados o reemplazados antes de la Gran Cruzada."},
  {t:"m",q:"\u00bfQu\u00e9 fue la Gran Cruzada?",o:["La expansi\u00f3n del Imperio para reunificar la humanidad bajo el Emperador", "Una invasi\u00f3n orka de Terra", "Una guerra skaven", "Una campa\u00f1a de Sigmar"],a:0,exp:"La Gran Cruzada fue la campa\u00f1a gal\u00e1ctica del Emperador para reunir mundos humanos dispersos.",extra:"Promet\u00eda una era racional e imperial, pero tambi\u00e9n implic\u00f3 conquista, exterminio xenos y sometimiento de culturas humanas independientes."},
  {t:"m",q:"\u00bfQu\u00e9 era la Verdad Imperial?",o:["Doctrina atea y racionalista del Imperio temprano", "Religi\u00f3n al Emperador Dios", "Dogma de los T\u2019au", "Culto de Marte"],a:0,exp:"La Verdad Imperial negaba dioses y superstici\u00f3n, promoviendo racionalismo y unidad humana.",extra:"Su gran iron\u00eda es que el Imperio moderno termin\u00f3 convertido en una teocracia que adora al Emperador como dios."},
  {t:"m",q:"\u00bfQu\u00e9 instituci\u00f3n religiosa adora al Emperador como dios en el Imperio moderno?",o:["Adeptus Ministorum", "Adeptus Mechanicus", "Navis Nobilite", "Officio Assassinorum"],a:0,exp:"El Adeptus Ministorum, o Ecclesiarchy, dirige la fe imperial.",extra:"Su poder espiritual y pol\u00edtico es inmenso, y su dogma sostiene a incontables mundos mediante fervor y miedo."},
  {t:"m",q:"\u00bfQu\u00e9 son los Servitors?",o:["Humanos lobotomizados convertidos en herramientas cyborg", "Demonios menores", "Nobles navegantes", "Astartes fallidos"],a:0,exp:"Los servitors son cuerpos humanos modificados y lobotomizados para cumplir tareas mec\u00e1nicas.",extra:"Son un ejemplo perfecto del horror cotidiano imperial: tecnolog\u00eda avanzada sostenida por pr\u00e1cticas deshumanizantes."},
  {t:"m",q:"\u00bfQu\u00e9 son los mundos forja?",o:["Planetas industriales del Adeptus Mechanicus", "Mundos agr\u00edcolas", "Planetas tumba necrones", "Santuarios Eldar"],a:0,exp:"Los mundos forja son planetas industriales controlados por el Adeptus Mechanicus.",extra:"Producen armas, veh\u00edculos, naves y municiones para el Imperio, a menudo contaminando y mecanizando todo el planeta."},
  {t:"m",q:"\u00bfQu\u00e9 son los mundos colmena?",o:["Planetas cubiertos por ciudades verticales gigantescas", "Planetas selv\u00e1ticos", "Mundos Eldar abandonados", "Planetas sin atm\u00f3sfera"],a:0,exp:"Los mundos colmena est\u00e1n dominados por enormes ciudades verticales con poblaciones inmensas.",extra:"Son motores industriales y demogr\u00e1ficos del Imperio, pero sus niveles bajos suelen ser infiernos de crimen, pobreza y contaminaci\u00f3n."},
];

export default warhammerQuestions;
